### showTooltip Function (lines 211-225)
```typescript
function showTooltip(dot: HTMLElement): void {
  dismissActiveTooltip();
  const content = contentFn(dot);
  const tooltip = document.createElement("div");
  tooltip.className = "chart-tooltip";
  renderTrustedHtml(tooltip, content);
  tooltip.style.position = "absolute";              // LINE 217

  const rect = dot.getBoundingClientRect();         // LINE 219
  tooltip.style.left = `${rect.left + rect.width / 2}px`;     // LINE 220
  tooltip.style.top = `${rect.top - 8}px`;                    // LINE 221
  tooltip.style.transform = "translateX(-50%) translateY(-100%)"; // LINE 222

  document.body.appendChild(tooltip);                // LINE 224
}
```

